L=http://judge-server:8080 - BACKEND_URL=http://oj-backend:8000/api/judge_server_heartbeat/ - TOKEN=CHANGE_THIS # - judger_debug=1 oj-backend: image: registry.cn-hangzhou.aliyuncs.com/onlinejudge/oj_backend container_name: oj-backend restart: always depends_on: - oj-redis - oj-postgres - judge-server volumes: - ./data/backend:/data environment: - POSTGRES_DB=onlinejudge - POSTGRES_USER=onlinejudge - POSTGRES_PASSWORD=onlinejudge - JUDGE_SERVER_TOKEN=CHANGE_THIS # - FORCE_HTTPS=1 # - STATIC_CDN_HOST=cdn.oj.com ports: - &quot;0.0.0.0:80:8000&quot; - &quot;0.0.0.0:443:1443&quot; ```bash 用脚本安装 HUSTOJ sudo bash install-ubuntu14.04.sh #!/bin/bashapt-get updateapt-get install -y subversion/usr/sbin/useradd -m -u 1536 judgecd /home/judge/svn co https://github.com/zhblue/hustoj/trunk/trunk/ src echo ‘mysql-server-5.5 mysql-server/root_password password “1”‘ | sudo debconf-set-selectionsecho ‘mysql-server-5.5 mysql-server/root_password_again password “”‘ | sudo debconf-set-selectionsapt-get install -y make flex g++ clang libmysqlclient-dev libmysql++-dev php5-fpm php5-memcache memcached nginx mysql-server php5-mysql php5-gd fp-compiler openjdk-7-jdkapt-get -y install language-pack-zh-hans USER=cat /etc/mysql/debian.cnf |grep user|head -1|awk '{print $3}'PASSWORD=cat /etc/mysql/debian.cnf |grep password|head -1|awk '{print $3}'CPU=grep &quot;cpu cores&quot; /proc/cpuinfo |head -1|awk '{print $4}'COMPENSATION=grep 'mips' /proc/cpuinfo|head -1|awk -F: '{printf(&quot;%.2f&quot;,$2/5000)}'mkdir etc data log backup cp src/install/java0.policy /home/judge/etccp src/install/judge.conf /home/judge/etcchmod +x src/install/ans2out if grep “OJ_SHM_RUN=0” etc/judge.conf ; then mkdir run0 run1 run2 run3 chown judge run0 run1 run2 run3 fi sed -i “s/OJ_USER_NAME=root/OJ_USER_NAME=$USER/g” etc/judge.confsed -i “s/OJ_PASSWORD=root/OJ_PASSWORD=$PASSWORD/g” etc/judge.confsed -i “s/OJ_RUNNING=1/OJ_RUNNING=$CPU/g” etc/judge.confsed -i “s/OJ_CPU_COMPENSATION=1.0/OJ_CPU_COMPENSATION=$COMPENSATION/g” etc/judge.conf sed -i “s/DB_USER[[:space:]]*=[[:space:]]&quot;root&quot;/DB_USER=&quot;$USER&quot;/g” src/web/include/db_info.inc.phpsed -i “s/DB_PASS[[:space:]]=[[:space:]]*&quot;root&quot;/DB_PASS=&quot;$PASSWORD&quot;/g” src/web/include/db_info.inc.phpchown -R www-data src/web/chown www-data src/web/upload dataif grep “client_max_body_size” /etc/nginx/nginx.conf ; then echo &quot;client_max_body_size already added&quot; ; else sed -i &quot;s:include /etc/nginx/mime.types;:client_max_body_size 80m;
	include /etc/nginx/mime.types;:g&quot; /etc/nginx/nginx.conf fi mysql -h localhost -u$USER -p$PASSWORD &lt; src/install/db.sqlecho “insert into jol.privilege values(‘admin’,’administrator’,’true’,’N’);”|mysql -h localhost -u$USER -p$PASSWORD sed -i “s#root /usr/share/nginx/html;#root /home/judge/src/web;

#g” /etc/nginx/sites-enabled/default#sed -i “s#root /usr/share/nginx/html;#root /home/judge/src/web;

	location /recent-contest.json {
