	}#g&quot; /etc/nginx/sites-enabled/defaultsed -i “s:index index.html:index index.php:g” /etc/nginx/sites-enabled/defaultsed -i “s:#location ~ \.php\$:location ~ \.php\$:g” /etc/nginx/sites-enabled/defaultsed -i “s:#	fastcgi_split_path_info:	fastcgi_split_path_info:g” /etc/nginx/sites-enabled/defaultsed -i “s:#	fastcgi_pass unix:	fastcgi_pass unix:g” /etc/nginx/sites-enabled/defaultsed -i “s:#	fastcgi_index:	fastcgi_index:g” /etc/nginx/sites-enabled/defaultsed -i “s:#	include fastcgi_params;:	include fastcgi_params;
	}:g” /etc/nginx/sites-enabled/default/etc/init.d/nginx restartsed -i “s/post_max_size = 8M/post_max_size = 80M/g” /etc/php5/fpm/php.inised -i “s/upload_max_filesize = 2M/upload_max_filesize = 80M/g” /etc/php5/fpm/php.inised -i ‘s/;request_terminate_timeout = 0/request_terminate_timeout = 128/g’ find /etc/php5 -name www.confsed -i ‘s/pm.max_children = 5/pm.max_children = 200/g’ find /etc/php5 -name www.conf /etc/init.d/php5-fpm restartservice php5-fpm restartcd src/corechmod +x ./make.sh./make.shif grep “/usr/bin/judged” /etc/rc.local ; then echo &quot;auto start judged added!&quot; else sed -i &quot;s/exit 0//g&quot; /etc/rc.local echo &quot;/usr/bin/judged&quot; &gt;&gt; /etc/rc.local echo &quot;exit 0&quot; &gt;&gt; /etc/rc.local fiif grep “bak.sh” /var/spool/cron/crontabs/root ; then echo &quot;auto backup added!&quot; else crontab -l &gt; conf &amp;&amp; echo &quot;1 0 * * * /home/judge/src/install/bak.sh&quot; &gt;&gt; conf &amp;&amp; crontab conf &amp;&amp; rm -f conf fi/usr/bin/judgedsystemctl enable hustojsystemctl enable nginxsystemctl enable mysqlsystemctl enable php7.3-fpmsystemctl enable judged clsreset echo “Remember your database account for HUST Online Judge:”echo “username:$USER”echo “password:$PASSWORD” 123453. ```sql insert into privilege(user_id,rightstr) values('123456','administrator');*--创建管理员账号123456 密码administrator*
